mapper.select:
SELECT id, employee_id, target_year, target_month, weekly_days, updated_at
FROM shift_request_settings
WHERE employee_id = #{employeeId}
  AND target_year = #{targetYear}
  AND target_month = #{targetMonth}

SELECT id, employee_id, request_date, request_slot, target_year, target_month, updated_at
FROM shift_request_days
WHERE employee_id = #{employeeId}
  AND target_year = #{targetYear}
  AND target_month = #{targetMonth}
ORDER BY request_date ASC

SELECT id, employee_id, request_date, request_slot, target_year, target_month, updated_at
FROM shift_request_days
WHERE target_year = #{targetYear}
  AND target_month = #{targetMonth}
ORDER BY employee_id ASC, request_date ASC

SELECT id, employee_id, target_year, target_month, weekly_days, updated_at
FROM shift_request_settings
WHERE target_year = #{targetYear}
  AND target_month = #{targetMonth}
ORDER BY employee_id ASC

